#nullable enable // autogenerated    
  
using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.GameContent.Buffs.Entities;    
using MVZ2.GameContent.Effects; // WaterStain  
using MVZ2.Vanilla.Level;    
using PVZEngine;    
using PVZEngine.Buffs;    
using PVZEngine.Definitions;    
using PVZEngine.Entities;    
using PVZEngine.Level;
using PVZEngine.Definitions;    
using UnityEngine;    
  
namespace MVZ2.GameContent.Stages    
{    
    [AutoStageDefinition(VanillaStageNames.ZombieNimbleZombieQuick)]    
    public partial class ZombieNimbleZombieQuickStage : StageDefinition    
    {    
        public ZombieNimbleZombieQuickStage(string nsp, string name) : base(nsp, name)    
        {    
            AddBehaviour(new WaveStageBehaviour(this));    
            AddBehaviour(new FinalWaveClearBehaviour(this));    
            AddBehaviour(new GemStageBehaviour(this));    
            AddBehaviour(new StarshardStageBehaviour(this));    
        }

        public override void OnUpdate(LevelEngine level)
        {
            base.OnUpdate(level);

            // รฟ3๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝาป๏ฟฝฮฃ๏ฟฝฮฌ๏ฟฝ๏ฟฝศซ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ  
            if (!level.IsTimeInterval(Ticks.FromSeconds(3f)))
                return;

            for (int col = 0; col < level.GetMaxColumnCount(); col++)
            {
                for (int lane = 0; lane < level.GetMaxLaneCount(); lane++)
                {
                    var grid = level.GetGrid(col, lane);
                    if (grid == null) continue;

                    float x = level.GetEntityColumnX(col);
                    float z = level.GetEntityLaneZ(lane);
                    float y = level.GetGroundY(x, z);
                    Vector3 pos = new Vector3(x, y, z);

                    var stain = WaterStain.UpdateStain(level, pos, null!);
                    if (stain != null)
                    {
                        // ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝหฎ๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝสน๏ฟฝ๏ฟฝ๏ฟฝฮช๏ฟฝ๏ฟฝ๏ฟฝ๏ฟฝ  
                        WaterStain.FreezeStain(stain);
                    }
                }
            }
        }

        public override void OnPostEnemySpawned(Entity entity)    
        {    
            base.OnPostEnemySpawned(entity);    
            AddSpeedBuff(entity);    
        }    
  
        private void AddSpeedBuff(Entity entity)    
        {    
            var buff = entity.AddBuff<MinigameEnemySpeedBuff>();    
            buff.SetProperty(MinigameEnemySpeedBuff.PROP_SPEED_MULTIPLIER,    
                Mathf.Lerp(MIN_SPEED, MAX_SPEED, entity.Level.CurrentWave / (float)entity.Level.GetTotalWaveCount()));    
        }    
  
        private const float MIN_SPEED = 1f;    
        private const float MAX_SPEED = 3f;    
    }    
}